import * as t from "io-ts";
import { RecipientEntry } from "./recipientEntry";
import { UnstakeIntent } from "./unstakeIntent";

/**
 * @title Near Unstake Intent
 */
export const NearUnstakeIntent = t.intersection([
  UnstakeIntent,
  t.type({
    recipients: t.array(RecipientEntry),
  }),
]);

export type NearUnstakeIntent = t.TypeOf<typeof NearUnstakeIntent>;
